CREATE TRIGGER LG_CLFLINE_DEL_123_01 ON LG_123_01_CLFLINE
FOR DELETE
AS
DECLARE @DT         DATETIME
DECLARE @MONTH      SMALLINT
DECLARE @YEAR       SMALLINT
DECLARE @TRCODE     SMALLINT
DECLARE @SIGN       SMALLINT
DECLARE @AMOUNT     FLOAT
DECLARE @REPORTNET  FLOAT
DECLARE @CLIENTREF  INT
DECLARE @MODULENR   SMALLINT
DECLARE @CANCELLED  SMALLINT
DECLARE @TRGFLAG    SMALLINT
DECLARE @REPORTRATE FLOAT
DECLARE @SOURCEFREF INT
DECLARE @STATUS     SMALLINT
DECLARE @AFFECTCOLLATRL SMALLINT
DECLARE @AFFECTRISK SMALLINT
DECLARE @PAIDINCASH SMALLINT
SELECT @DT = D.DATE_,
       @MONTH  = D.MONTH_,
       @YEAR   = D.YEAR_,
       @TRCODE = D.TRCODE,
       @SIGN = D.SIGN,
       @AMOUNT = D.AMOUNT,
       @REPORTNET = D.REPORTNET,
       @CLIENTREF = D.CLIENTREF,
       @MODULENR = D.MODULENR,
       @CANCELLED = D.CANCELLED,
       @TRGFLAG = D.TRGFLAG,
       @REPORTRATE = D.REPORTRATE,
       @SOURCEFREF = D.SOURCEFREF,
       @STATUS = D.STATUS,
       @AFFECTCOLLATRL = D.AFFECTCOLLATRL,
       @AFFECTRISK = D.AFFECTRISK,
       @PAIDINCASH = D.PAIDINCASH   FROM DELETED D
IF (@TRGFLAG <> 1)
 EXECUTE LG_UPDATE_CLTRANS_123_01 -1, @TRCODE, @SIGN, @AMOUNT, @REPORTNET, @CLIENTREF,
                                 @MODULENR, @CANCELLED, @REPORTRATE, @STATUS, @AFFECTCOLLATRL, @AFFECTRISK, @PAIDINCASH, 0
